codeComparison.old:
/* Images are inline by default - gap below! */
.image-container img {
  max-width: 100%;
}

codeComparison.new:
/* Fix: make image block to remove gap */
.image-container img {
  max-width: 100%;
  display: block;
}

/* Buttons side by side with inline-block */
.btn {
  display: inline-block;
  background-color: #007bff;
  color: white;
  padding: 12px 24px;
  border: none;
  border-radius: 4px;
  margin-right: 10px;
}
